``` json
{
    "elements": 
[
    {
        "id": "qi9mnkIJEeWC4g7VhG4bTQ~F1pTC",
        "courseId": "qi9mnkIJEeWC4g7VhG4bTQ",
        "itemId": "F1pTC"
    }
],
"paging": null,
"linked": 
{
